      .then(r => r.json())
      .then(setData);
  }, [deptId]);

  return (
    <div>
      <SectionTitle>Monthly Reports</SectionTitle>
      <Card style={{ marginBottom: 20 }}>
        <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
          <label style={{ fontSize: 13, color: "#6b7280" }}>Filter by department:</label>
