                  {row.variance > 0 ? "▲ " : "▼ "}{fmt(Math.abs(row.variance))}
                </td>
              </tr>
            ))}
            {data.length === 0 && (
              <tr><td colSpan={4} style={{ padding: 24, textAlign: "center", color: "#9ca3af" }}>No data for this selection.</td></tr>
            )}
          </tbody>
        </table>
